def {{nama_fungsi}}(steps, initial_input, caller_func):
    """Jalankan rantai prompt linear.
    steps: list of callable(input_text) -> prompt_text, atau string template.
    caller_func: callable(prompt_text) -> response_text.
    Kembalikan dict {step_index: output} dan output akhir.
    """
    history = {}
    current_input = initial_input
    for idx, step in enumerate(steps):
        if callable(step):
            prompt = step(current_input)
        else:
            prompt = str(step).replace("{input}", current_input)
        response = caller_func(prompt)
        history[idx] = {"prompt": prompt, "response": response}
        current_input = response
    return {"steps": history, "final_output": current_input}
